mapper.select:
select s.storeId,s.storeName,s.storeAddrId,s.storeImgUrl,s.storePhone,s.hours,s.storeArea,s.createdDate,s.status, s.agent5Ids,agent6Ids, concat(sa.province,sa.city,sa.zone,sa.storeAddrDetail) as storeAddr, sa.province,sa.city,sa.zone,sa.storeAddrDetail,sa.longitude,sa.latitude,sa.goodsIdStoreId,sa.douyin_poi_id as douyinPoiId, (select count(*) from store_device sd inner join face_identy_record fir on sd.deviceNo=fir.deviceNo where sd.storeId=#{storeId}) as currentNum from store s inner join store_address sa on sa.storeAddrId=s.storeAddrId
AND s.storeId = #{storeId}
AND s.storeId in (${storeIds})
AND s.storeName LIKE concat('%',#{storeName},'%')
AND s.storePhone LIKE concat('%',#{storePhone},'%')
AND s.status = #{status}
AND sa.goodsIdStoreId = #{goodsIdStoreId}
AND sa.douyin_poi_id = #{douyinPoiId}
AND find_in_set(#{agent5Ids}, agent5Ids)
AND find_in_set(#{agent6Ids}, agent6Ids)
order by ${sidx} ${order}
order by s.createdDate desc
limit #{offset}, #{limit}

select count(*) from store s
inner join store_address sa on sa.storeAddrId=s.storeAddrId
            
    
        AND s.storeId = #{storeId}
    
    
        AND s.storeId in (${storeIds})
    
    
        AND s.storeName LIKE concat('%',#{storeName},'%')
    
    
        AND s.storePhone LIKE concat('%',#{storePhone},'%')
    
    
        AND s.status = #{status}
    
    
        AND sa.goodsIdStoreId = #{goodsIdStoreId}
    
    
        AND sa.douyin_poi_id = #{douyinPoiId}
    
    
        AND find_in_set(#{agent5Ids}, agent5Ids)
    
    
        AND find_in_set(#{agent6Ids}, agent6Ids)

select ac.arrangeClassId, ac.classPlace as storeName, ac.className, ac.classTime, date_format(ac.validityDate, '%Y-%m-%d %H:%i') as validityDate, ac.duration, ac.price, ac.classStatus, sps.orderNo, sps.askNumber, sps.buyNumber, sps.energy, co.coachName, co.phone as coachPhone, ui.nickname, ui.phone as stuPhone from arrange_class ac inner join stu_privateclass_ship sps on sps.spsId = ac.spsId left join coach co on co.coachId = ac.coachId left join user_info ui on ui.userId = ac.studentId
ac.classPlaceId = #{classPlaceId}
and ac.classStatus = #{classStatus}
AND co.storeId in (${storeIds})
and sps.orderNo like concat('%', trim(#{orderNo}),'%')
and ui.phone like concat('%', trim(#{stuPhone}),'%')
and co.phone like concat('%', trim(#{coachPhone}),'%')
order by STR_TO_DATE(ac.classTime, '%Y-%m-%d %H:%i') desc LIMIT #{offset}, #{limit}

select sts.stuTeamClassId, sts.classId, sts.orderNo, sts.className, sts.classroom, sts.classAddress, sts.classTime, sts.classStatus, sts.coachName, sts.energy, ui.nickname, ui.phone as stuPhone from stu_teamclass_ship sts left join user_info ui on ui.userId = sts.studentId
sts.storeId = #{storeId}
and sts.classId like concat('%',#{classId},'%')
and sts.classStatus = #{classStatus}
and sts.orderNo like concat('%',trim(#{orderNo}),'%')
and ui.phone like concat('%', trim(#{stuPhone}),'%')
order by STR_TO_DATE(sts.createdDate, '%Y-%m-%d %H:%i') desc LIMIT #{offset}, #{limit}

select
count(*)
from stu_teamclass_ship sts
left join user_info ui on ui.userId = sts.studentId

    
        sts.storeId = #{storeId}
    
    
        and sts.classId = #{classId}
    
    
        and sts.classStatus = #{classStatus}
    
    
        and sts.orderNo = trim(#{orderNo})
    
    
        and ui.phone = trim(#{stuPhone})

